DROP TEMPORARY TABLE IF EXISTS `tmp_seed_private_buses`;
CREATE TEMPORARY TABLE `tmp_seed_private_buses` (
  `reg_no` varchar(20) NOT NULL,
  PRIMARY KEY (`reg_no`)
) ENGINE=MEMORY;

